  ('police-b20a8cf8-moex-00444', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '血跡噴濺痕中，大部分的血滴直徑為2毫米或小於2毫米者，通常是高速撞擊的血跡型態，下列 何者通常不會造成高速噴濺血跡型態？', '["爆炸", "槍擊", "高速公路的車禍撞擊", "菜刀砍殺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
