  ('police-b20a8cf8-moex-00448', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '破裂的玻璃通常與竊案、槍擊、火災等案件相關，由玻璃裂痕可研判的資訊，下列敘述何者正確？', '["撞擊力的方向（如由內而外）", "撞擊力的角度", "槍擊順序", "燃燒的溫度  ⑤燃燒行進方向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00449', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'essay', '重大刑案發生除立即偵破外，均應訂定偵查計畫，以為偵查之準據；若
轄內發生一男子被人發現身上有多處刀傷倒臥其住家門口，大量流血而
死亡，未立即偵破，你若要訂定偵查計畫，其內容應為何？請詳述之。
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00450', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'essay', '若你是偵查員接獲線民通報：「轄內工業區某倉儲內，有人從泰國進口木
材，卻夾帶大量海洛因。」經派員監控該倉儲，發現一可疑車輛（車主
甲曾為毒品人口），多次進出該倉儲。請問警方應如何進行偵查作為並擴
大偵破？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00451', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察偵查犯罪手冊中重大刑案、特殊刑案與一般刑案之規定，下列敘述何者正確？', '["重大刑案、特殊刑案與一般刑案之區分，主要是考量偵查資源之有效運用，與被害者權益無關", "縣市警察局發生重大群毆械鬥案件，得由署長指派刑事警察局主動支援、合力偵辦", "縣市警察局發生擄人勒贖案件，刑事警察局得不經申請，逕行派員支援", "分局偵辦查獲300包新興毒品（咖啡包）案件，如發覺案情複雜，得移請警察局辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00452', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察機關分局偵查隊及分駐所或派出所偵辦案件聯繫事項，下列敘述何者正確？', '["分駐所或派出所員警查獲現行犯案件，應立即通報分局偵查隊，由分局長決定是否指派刑事人 員前往協助", "犯罪嫌疑人已拘提且犯罪事證明確之普通刑案，由分駐所或派出所主辦", "分駐所或派出所辦理案件逮捕嫌疑人有數人時，為避免逾越法定時效，應立即請求偵查隊協助 偵辦", "重大刑案及後續需追查案件，由分駐所或派出所主管視案情複雜情形，判斷是否自行偵辦或陳 報偵查隊偵辦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00453', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關刑事案件告訴，下列敘述何者正確？', '["告訴乃論期間係以知悉犯人之時開始起算6個月，所謂知悉只須達到懷疑，無須達到實證或確 信之程度", "為減輕人民訟累，警方受理告訴乃論案件後，應協助民眾向鄉（鎮、市、區）調解委員會聲請 調解", "告訴人對鬥毆共犯一人撤回傷害罪告訴，其效力不及於其他共犯", "受理告訴乃論案件後，若為無得為告訴權人之情形，應送檢察官核辦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
